"""platformdirs.unix — Unix/Linux path resolver stub.

iOS doesn't run on Unix paths (the app sandbox + ``sys.platform == 'ios'``
sends every call through the MacOS resolver), but platformdirs imports
this submodule unconditionally during package init. Provide a minimal
``Unix`` class so the import succeeds; the methods delegate to the
MacOS implementation since iOS has the same XDG-less Cocoa filesystem
layout.

This stub is only used when platformdirs is bundled inside CodeBench;
on a real Linux desktop you'd want the upstream module."""


from __future__ import annotations

import os

from platformdirs.macos import MacOS


class Unix(MacOS):
    """XDG-ish dirs on iOS — delegates to the MacOS resolver.

    Subclasses :class:`platformdirs.macos.MacOS` so every ``user_*`` /
    ``site_*`` property is inherited verbatim. If platformdirs ever
    routes here at runtime (it normally won't on darwin / ios), the
    user still gets sensible paths instead of an ImportError.
    """

    # Upstream's Unix resolver honours XDG_* env vars before falling
    # back to ~/.local/share etc. The few callers that *do* land here
    # mostly want a writable cache/config dir — MacOS gives them that.

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)


__all__ = ['Unix']
